// src/App.js 
import { BrowserRouter, Routes, Route } from 'react-router-dom'; 
import SplashPage from './pages/SplashPage'; 
import HomePage from './pages/HomePage'; 
import AboutPage from './pages/AboutPage'; 
import ContactPage from './pages/ContactPage'; import RegisterPage from './pages/RegisterPage'; 
function App() { 
return ( 
<BrowserRouter> 
<Routes> 
<Route path='/' element={<SplashPage />} /> <Route path='/home' element={<HomePage />} /> <Route path='/about' element={<AboutPage />} /> <Route path='/contact' element={<ContactPage />} /> <Route path='/register' element={<RegisterPage />} /> </Routes> 
</BrowserRouter> 
); 
} 
export default App;
